mapper.select:
SELECT b.vip_benefit_id AS vipBenefitId, b.origin_user_id AS originUserId, ou.nickname AS originNickname, ou.phone AS originPhone, b.user_id AS userId, hu.nickname AS holderNickname, hu.phone AS holderPhone, b.vip_card_id AS vipCardId, c.card_name AS cardName, b.source_order_no AS sourceOrderNo, b.origin_price AS originPrice, b.transfer_count AS transferCount, b.start_time AS startTime, b.expire_time AS expireTime, b.status AS status, b.created_date AS createdDate FROM vip_benefit b LEFT JOIN user_info ou ON b.origin_user_id = ou.userId LEFT JOIN user_info hu ON b.user_id = hu.userId LEFT JOIN vip_benefit_card c ON b.vip_card_id = c.vip_card_id
ORDER BY b.created_date DESC
LIMIT #{offset}, #{limit}
